namespace sv_ca0895dbd44a44febcc52eeee515bbe7.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@page "/catalog"
@using sv_ca0895dbd44a44febcc52eeee515bbe7.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<div class="d-flex gap-4">
    <!-- Sidebar Filters -->
    <aside class="catalog-sidebar">
        <h5 class="mb-3">Filters</h5>

        @if (categories is not null)
        {
            <div class="mb-3">
                <label class="form-label fw-semibold">Category</label>
                @foreach (var cat in categories)
                {
                    <div class="form-check">
                        <input class="form-check-input" type="checkbox" id="@($"cat-{cat}")"
                               checked="@selectedCategories.Contains(cat)"
                               @onchange="e => ToggleCategory(cat, (bool)e.Value!)" />
                        <label class="form-check-label" for="@($"cat-{cat}")">@cat</label>
                    </div>
                }
            </div>
        }

        <div class="mb-3">
            <label class="form-label fw-semibold">Price Range</label>
            <div class="d-flex gap-2">
                <input type="number" class="form-control form-control-sm" placeholder="Min"
                       @bind="minPrice" @bind:event="oninput" min="0" step="0.01" />
                <input type="number" class="form-control form-control-sm" placeholder="Max"
                       @bind="maxPrice" @bind:event="oninput" min="0" step="0.01" />
            </div>
        </div>

        <div class="mb-3 form-check">
            <input class="form-check-input" type="checkbox" id="inStockOnly" @bind="inStockOnly" />
            <label class="form-check-label" for="inStockOnly">In Stock Only</label>
        </div>

        <div class="d-grid gap-2">
            <button class="btn btn-primary btn-sm" @onclick="ApplyFilters">Apply Filters</button>
            <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFilters">Clear Filters</button>
        </div>
    </aside>

    <!-- Main Content -->
    <main class="flex-grow-1">
        @if (errorMessage is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @errorMessage
            </div>
        }
        else if (isLoading)
        {
            <div class="d-flex justify-content-center align-items-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else if (result is not null)
        {
            <!-- Toolbar -->
            <div class="d-flex justify-content-between align-items-center mb-3">
                <div>
                    <label class="form-label me-2 mb-0" for="sortSelect">Sort by:</label>
                    <select id="sortSelect" class="form-select form-select-sm d-inline-block w-auto"
                            @bind="sortBy" @bind:after="OnSortChanged">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A-Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>
                <span class="text-muted">
                    Showing @(ShowingStart)–@(ShowingEnd) of @result.TotalCount products
                </span>
            </div>

            @if (result.Items.Count == 0)
            {
                <div class="text-center py-5 text-muted">
                    <h5>No products found</h5>
                    <p>Try adjusting your filters or clearing them to see all products.</p>
                </div>
            }
            else
            {
                <!-- Product Grid -->
                <div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3 mb-4">
                    @foreach (var product in result.Items)
                    {
                        <div class="col">
                            <ProductCard Product="product"
                                         OnProductClicked="HandleProductClicked"
                                         OnAddToCart="HandleAddToCart" />
                        </div>
                    }
                </div>

                <!-- Pagination -->
                @if (TotalPages > 1)
                {
                    <nav aria-label="Product pagination">
                        <ul class="pagination justify-content-center">
                            <li class="page-item @(currentPage == 1 ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPage(currentPage - 1)"
                                        disabled="@(currentPage == 1)">Previous</button>
                            </li>
                            @foreach (var p in PageNumbers)
                            {
                                <li class="page-item @(p == currentPage ? "active" : "")">
                                    <button class="page-link" @onclick="() => GoToPage(p)">@p</button>
                                </li>
                            }
                            <li class="page-item @(currentPage == TotalPages ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPage(currentPage + 1)"
                                        disabled="@(currentPage == TotalPages)">Next</button>
                            </li>
                        </ul>
                    </nav>
                }
            }
        }
    </main>
</div>

@code {
    private List<string>? categories;
    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 9;

    private PagedResult<Product>? result;
    private bool isLoading = true;
    private string? errorMessage;

    private int ShowingStart => result is null || result.Items.Count == 0 ? 0 : (result.Page - 1) * result.PageSize + 1;
    private int ShowingEnd => result is null ? 0 : Math.Min(result.Page * result.PageSize, result.TotalCount);
    private int TotalPages => result is null || result.PageSize == 0 ? 0 : (int)Math.Ceiling((double)result.TotalCount / result.PageSize);

    private IEnumerable<int> PageNumbers
    {
        get
        {
            int total = TotalPages;
            int start = Math.Max(1, currentPage - 2);
            int end = Math.Min(total, start + 4);
            start = Math.Max(1, end - 4);
            return Enumerable.Range(start, end - start + 1);
        }
    }

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            var categoriesTask = categories is null
                ? ProductService.GetCategoriesAsync()
                : Task.FromResult(categories);
            var searchTask = ProductService.SearchAsync(BuildFilter(), sortBy, currentPage, PageSize);

            await Task.WhenAll(categoriesTask, searchTask);

            categories = await categoriesTask;
            result = await searchTask;
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private ProductFilter BuildFilter() => new(
        Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
        MinPrice: minPrice,
        MaxPrice: maxPrice,
        InStockOnly: inStockOnly
    );

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        currentPage = 1;
        await LoadDataAsync();
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        currentPage = 1;
        await LoadDataAsync();
    }

    private async Task OnSortChanged()
    {
        currentPage = 1;
        await LoadDataAsync();
    }

    private async Task GoToPage(int page)
    {
        if (page < 1 || page > TotalPages) return;
        currentPage = page;
        await LoadDataAsync();
    }

    [Parameter]
    public EventCallback<int> OnProductSelected { get; set; }

    private async Task HandleProductClicked(Product product)
    {
        await OnProductSelected.InvokeAsync(product.Id);
    }

    private void HandleAddToCart(Product product)
    {
        // Placeholder for cart integration
    }
}

.catalog-sidebar {
    width: 25%;
    min-width: 220px;
    max-width: 300px;
    border-right: 1px solid #dee2e6;
    padding-right: 1rem;
}

@using sv_ca0895dbd44a44febcc52eeee515bbe7.Services

<div class="card h-100 product-card" @onclick="OnCardClicked" role="button">
    <div class="card-img-placeholder d-flex align-items-center justify-content-center bg-light"
         role="img" aria-label="@Product.Name">
        <span class="text-muted small text-center px-2">@Product.Name</span>
    </div>
    <div class="card-body d-flex flex-column">
        <h6 class="card-title mb-1">@Product.Name</h6>
        <p class="card-text fw-bold text-primary mb-1">@Product.Price.ToString("C")</p>
        <div class="mb-2" title="@($"{Product.Rating:F1} out of 5")">
            @RatingStars
        </div>
        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2">Out of Stock</span>
        }
        <button class="btn btn-sm btn-success mt-auto"
                disabled="@(!Product.InStock)"
                @onclick="OnAddToCartClicked"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnProductClicked { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private string RatingStars
    {
        get
        {
            int filled = (int)Math.Round(Product.Rating);
            return new string('★', filled) + new string('☆', 5 - filled);
        }
    }

    private async Task OnCardClicked()
    {
        await OnProductClicked.InvokeAsync(Product);
    }

    private async Task OnAddToCartClicked()
    {
        await OnAddToCart.InvokeAsync(Product);
    }
}

.product-card {
    cursor: pointer;
    transition: box-shadow 0.2s ease, transform 0.2s ease;
}

.product-card:hover {
    box-shadow: 0 0.25rem 0.75rem rgba(0, 0, 0, 0.15);
    transform: translateY(-2px);
}

.card-img-placeholder {
    height: 160px;
    border-bottom: 1px solid #dee2e6;
}

